import{c as t,Q as o,j as a,m as r}from"./chunks/framework.BXc4yaFE.js";const m=JSON.parse(`{"title":"Ben's Bites — 2026-04-28","description":"","frontmatter":{"title":"Ben's Bites — 2026-04-28","date":"2026-04-28T00:00:00.000Z","source":"Ben's Bites","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-04/2026-04-28-bens-bites.md","filePath":"research/ai-news/2026-04/2026-04-28-bens-bites.md","lastUpdated":1779935873000}`),n={name:"research/ai-news/2026-04/2026-04-28-bens-bites.md"};function s(i,e,u,l,p,h){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="🍔-ben-s-bites-—-2026-04-28" tabindex="-1">🍔 Ben&#39;s Bites — 2026-04-28 <a class="header-anchor" href="#🍔-ben-s-bites-—-2026-04-28" aria-label="Permalink to &quot;🍔 Ben&#39;s Bites — 2026-04-28&quot;">​</a></h1><blockquote><p>Ben Tossell 的 AI 日報，工具圈消息源 來源：<a href="https://www.bensbites.com/feed" target="_blank" rel="noreferrer">Ben&#39;s Bites</a></p></blockquote><hr><h2 id="builders" tabindex="-1"><a href="https://www.bensbites.com/p/builders" target="_blank" rel="noreferrer">Builders</a> <a class="header-anchor" href="#builders" aria-label="Permalink to &quot;[Builders](https://www.bensbites.com/p/builders)&quot;">​</a></h2><p><em>🍔 Ben&#39;s Bites | 2026-04-28</em></p><p>Hey folks,</p><p>I spent most of last week in San Francisco, but mostly sat in my hotel obsessing over my Stanford talk while trying to work out where I’d find the specific colour presents my kids had requested. Arabella wanted purple. Max wanted green.</p><p>Jenni is the main reason I went to SF. She invited me to Stanford and it was such a privilege. Plus, she’s brilliant. Sharp, high-agency, but warm and very personable. She also runs an <a href="https://www.steigerbean.com/" target="_blank" rel="noreferrer">AI consultancy for CEOs</a> and gets my highest recommendation. If you get the chance to work with her, take it.</p><p>SF has this energy - how do I go faster, grow bigger, become more successful?</p><p>I get it. I like that energy. But I also came home thinking that my own version of ambition looks a bit different.</p><p>Yesterday I finally read the <a href="https://review.firstround.com/reluctantly-influential-inside-lenny-rachitskys-demandingly-chill-life/" target="_blank" rel="noreferrer">profile of Lenny</a> from Lenny’s Newsletter and a lot of it stuck with me. Because it was about building a life where you can care deeply about the work without letting the work eat everything else.</p><p>That felt so ‘me’ I had to text him and let him know!</p><p>I spent an unreasonable amount of time on my Stanford talk. Not because I didn’t know what I wanted to say, but because I cared about how it landed and was presented. And also because I was trying to make the course and the talk at the same time.</p><p>Working on it also made it clearer to me that I sit in this weird middle ground where non-technical people think I’m technical, and developers don’t. But I think a lot of you are somewhere in that messy middle too. Truth is, it’s all a bit messy - everyone is still figuring out agents and AI.</p><p>Working with agents isn’t about becoming a developer, but understanding the shape of things; files, tools, systems. With a thick dollop of taste on top.</p><p>If you can steer agents, you can get technical pretty quickly. I did. You just have to be realistic that you’ll hit tons of bumps in the road. Your job is to use your agent to figure it out - and you’ll probably learn something that’ll come up again and again.</p><p>That’s what I want Ben’s Bites to be more about. Taking you along my exploration: what I’m seeing, what I’m trying, how I’m thinking about it, what bumps I ran into, come along and try whatever sounds useful. Too much ‘education’ out there is just thirsty growth-hacks to sell you something.</p><p>I’ve sold a company. I’ve got three tiny kids at home. I want to do excellent work, make good money, back great companies, and build something useful without accidentally creating a job I don’t want.</p><p>There are big, valuable companies that want me to work with them. They’d give me clout, access, money. But I hesitate because I don’t know if I can give that kind of thing my all.</p><p>Even with my fund. I’m invested in funds who have more money, better process, bigger pipelines. And yet my funds are outperforming.</p><p>But I struggle to fundraise because my story isn’t presented cleanly and my process doesn’t look like a workflow. I tinker. I talk to developers. I try tools. I see what people click. I back founders building things I think will matter.</p><p>It’s all connected. The newsletter gives me a read on what builders care about. The fund lets me back the tools that might become important. The course/workshop stuff is me trying to teach the shift I’m living through myself.</p><p>Devtools built for developers today become the tools agents use. Humans steering, agents operating. They’ll pick up the tools, compose them, run the commands, change the files, connect the systems.</p><p>We just gotta understand enough of the shape of the work to direct it well.</p><p>A lot of what I do comes down to feel. Caring about the thing enough to make it good, but not needing to turn every good thing into a machine. And squeezing every last drop for growth’s sake.</p><p>So I came back from SF without a plan to scale. Mostly I came back thinking, I want to keep building for this new class of builders. People who are curious, increasingly technical, and trying to use AI to become more capable.</p><p>That feels like a good place to spend my time. Raising the floor, not the ceiling (h/t Jenni/Jen’s Bites).</p><p>Exploring, tinkering and teaching.</p><p>p.s. the kids got their toys, and I’ll continue working on the ‘course’ with care 😊</p><p>p.p.s. speaking of care, my brother Adam just launched <a href="https://honoui.com/" target="_blank" rel="noreferrer">Hono UI</a> - a UI kit (like Shadcn) but for projects that use Hono. Proud of him! Do me a favour and <a href="https://x.com/AdamTossell/status/2049124893426413809" target="_blank" rel="noreferrer">blow up his launch post</a> 🙏</p><p>Ben’s Bites is brought to you by <a href="https://attio.com/?utm_source=bens_bites&amp;utm_medium=newsletter_sponsorship&amp;utm_campaign=bens_bites-Y26" target="_blank" rel="noreferrer">Attio</a>, the AI CRM</p><p>Honestly, no one gets excited about a CRM. But then they try <a href="https://attio.com/?utm_source=bens_bites&amp;utm_medium=newsletter_sponsorship&amp;utm_campaign=bens_bites-Y26" target="_blank" rel="noreferrer">Attio</a>. It connects to Claude Code and n8n through its MCP server, completely bridging the gap between my customer data and apps. Wait, there&#39;s more, like flagging churn risk and turning customer feedback into Linear projects. <a href="https://attio.com/?utm_source=bens_bites&amp;utm_medium=newsletter_sponsorship&amp;utm_campaign=bens_bites-Y26" target="_blank" rel="noreferrer">Try it now</a>.</p><p>Headlines</p><p><a href="https://openai.com/index/introducing-gpt-5-5/" target="_blank" rel="noreferrer">OpenAI released GPT-5.5</a> - On paper, it’s a much better model than Opus 4.7 (minus frontend design - but using their new image gen model and asking 5.5 to turn that into code is a great workaround). This comes with a price increase making it 2x more expensive than GPT-5.4 and even slightly more than Opus 4.7 on a per-token basis. But claims it’s 40% more token efficient, so per-task cost doesn&#39;t change much (Ramp reported <a href="https://x.com/rahulgs/status/2048830174524063752" target="_blank" rel="noreferrer">similar results</a>).</p><p>It’s become my default model since Anthropic cracked down on usage outside of their own harness. I’m in ‘thinking:low’ camp, super smart and fast.</p><p>I’m also trying to use the codex desktop app over a terminal and there’s lots to like - but I’m just desperate for cloud/mobile use too.</p><p>One more thing… it’s clear OpenAI is focusing on builders, they’re shipping like crazy, are very vocal on X, responding to users and resetting rate limits. We love to see it.</p><p><a href="https://www.anthropic.com/engineering/april-23-postmortem" target="_blank" rel="noreferrer">Claude got worse</a>. It’s official. Anthropic posted a breakdown of what and why it happened. Basically, changing the default thinking mode and system prompt changes led to a combined fall in the quality of Claude&#39;s responses, especially in Claude Code. They still clarify that they don’t switch to a quantised or “worse” model.</p><p><a href="https://x.com/claudeai/status/2047421844311949513" target="_blank" rel="noreferrer">Memory on Claude Managed Agents</a> is now in public beta. Context: Managed Agents is Claude’s API product for companies to easily plug in claude code-like agents into their products without managing the hassle of infrastructure.</p><p>Cursor needs compute and a model. XAI needs users. And competition is higher than ever for coding agents. Cursor was raising $2Bn at $50Bn but has been paused because they struck a deal with SpaceX/XAI that gives SpaceX the option to <a href="https://x.com/SpaceX/status/2046713419978453374" target="_blank" rel="noreferrer">buy Cursor for $60B later in 2026</a>, or instead pay $10B for the collaboration. It’s a weird structure I’ve not seen before - so we will see what happens. Never a dull day.</p><p>Your CRM knows nothing because you never update it. Lightfield captures every email, call, and meeting automatically — then lets you ask anything. “Why do we keep losing to [competitor]?” Real answers from real conversations. <a href="https://lightfield.app/clp/default-1?utm_source=newsletter&amp;utm_medium=paid&amp;utm_campaign=bens_bites&amp;utm_content=secondary_4-28-2026" target="_blank" rel="noreferrer">Get 3 months off with code BENSBITESS13</a>.*</p><p>My feed</p><p><a href="https://trismik.com/?utm_source=bens_bites&amp;utm_medium=newsletter&amp;utm_campaign=bens_bites" target="_blank" rel="noreferrer">QuickCompare</a> helps you choose the right LLM for your use case. Compare 50+ models on your own data in minutes with Trismik. Try free now!*</p><p><a href="https://x.com/zan2434/status/2046982383430496444" target="_blank" rel="noreferrer">Flipbook</a> - every pixel on your screen, streamed live directly from a model. Another <a href="https://x.com/JohannesMutter/status/2047071831857774594" target="_blank" rel="noreferrer">similar demo</a>.</p><p><a href="https://x.com/FarzaTV/status/2048203459976188261" target="_blank" rel="noreferrer">Clicky</a> lets you talk to AI and spawn an agent on your Mac. Farza built and open-sourced a version of this a few days ago, but the new clicky is closed source. OpenAI already had a version of this <a href="https://x.com/OpenAIDevs/status/2048871260512473385" target="_blank" rel="noreferrer">which you can clone</a>.</p><p>Things I learned <a href="https://semaphore.substack.com/p/things-i-learned-at-openai" target="_blank" rel="noreferrer">working at OpenAI</a>.</p><p><a href="https://x.com/NaderLikeLadder/status/2048895607461552141" target="_blank" rel="noreferrer">AI isn’t replacing anyone</a>.</p><p><a href="https://x.com/ExaAILabs/status/2047735503794094485" target="_blank" rel="noreferrer">Exa for Claude</a> - plugin to give your Claude access to websites, people, companies, and more.</p><p><a href="https://ora.run/" target="_blank" rel="noreferrer">Ora.run</a> - scan and rank how well agents can find and use your business.</p><p><a href="https://tolaria.md/" target="_blank" rel="noreferrer">Tolaria</a> is another app to read/write markdown files on your desktop with second-brain-esque features.</p><p><a href="https://x.com/katedeyneka/status/2047359633342517718" target="_blank" rel="noreferrer">Reelful</a> - from a camera roll to a finished reel in just 10 minutes.</p><p><a href="https://github.com/layerbrain/trunks" target="_blank" rel="noreferrer">trunks by layerbrain</a> - turn your own storage into git remote with a minimal CLI.</p><p><a href="https://github.com/Dhravya/webpull" target="_blank" rel="noreferrer">webpull</a> - instantly pull any website into a directory of clean, searchable markdown files.</p><p><a href="https://github.com/vincentkoc/slacrawl" target="_blank" rel="noreferrer">slacrawl</a> - cli terminal app for slack with sqlite backend.</p><p><a href="https://claude.com/blog/building-agents-that-reach-production-systems-with-mcp" target="_blank" rel="noreferrer">When and how to use MCP</a> for apps built for production.</p><p><a href="https://github.com/OpenRouterTeam/skills/tree/main/skills/create-agent-tui" target="_blank" rel="noreferrer">create-agent-tui</a> - skill for building your own agent harness + terminal UI.</p><p>Aman (ex-Harvey) built an offline AI app to track his skin’s response to different diets and products with local models. (<a href="https://testflight.apple.com/join/kMbzKbtt" target="_blank" rel="noreferrer">testflight</a>) (<a href="https://x.com/_amankishore/status/2047341809626448242" target="_blank" rel="noreferrer">how he built it</a>)</p><p>OpenAI is updating its <a href="https://openai.com/index/next-phase-of-microsoft-partnership/" target="_blank" rel="noreferrer">partnership with Microsoft</a>. Separately, <a href="https://www.youtube.com/watch?v=NCKQL0op30E" target="_blank" rel="noreferrer">Sam and Greg</a> did an interview recently (their first one together?)</p><p>Afters</p><p>Sinceerly.com &quot;,&quot;username&quot;:&quot;horwitzben&quot;,&quot;name&quot;:&quot;Ben Horwitz&quot;,&quot;profile_image_url&quot;:&quot;<a href="https://pbs.substack.com/profile_images/1903833767028174848/nRx7s42A_normal.jpg%22,%22date%22:%222026-04-23T12:36:33.000Z%22,%22photos%22:%5B%7B%22img_url%22:%22https://substackcdn.com/image/upload/w_1028,c_limit,q_auto:best/l_twitter_play_button_rvaygk,w_88/b8e6vwgdlcffhzuiqjkj%22,%22link_url%22:%22https://t.co/1AF5qrCFwT%22%7D%5D,%22quoted_tweet%22:%7B%7D,%22reply_count%22:449,%22retweet_count%22:626,%22like_count%22:11768,%22impression_count%22:2080625,%22expanded_url%22:null,%22video_url%22:%22https://video.twimg.com/amplify_video/2047293337388900352/vid/avc1/720x726/gcQlKtAIQsvF7yl1.mp4?tag=14%22,%22belowTheFold%22:true%7D%22" target="_blank" rel="noreferrer">https://pbs.substack.com/profile_images/1903833767028174848/nRx7s42A_normal.jpg&quot;,&quot;date&quot;:&quot;2026-04-23T12:36:33.000Z&quot;,&quot;photos&quot;:[{&quot;img_url&quot;:&quot;https://substackcdn.com/image/upload/w_1028,c_limit,q_auto:best/l_twitter_play_button_rvaygk,w_88/b8e6vwgdlcffhzuiqjkj&quot;,&quot;link_url&quot;:&quot;https://t.co/1AF5qrCFwT&quot;}],&quot;quoted_tweet&quot;:{},&quot;reply_count&quot;:449,&quot;retweet_count&quot;:626,&quot;like_count&quot;:11768,&quot;impression_count&quot;:2080625,&quot;expanded_url&quot;:null,&quot;video_url&quot;:&quot;https://video.twimg.com/amplify_video/2047293337388900352/vid/avc1/720x726/gcQlKtAIQsvF7yl1.mp4?tag=14&quot;,&quot;belowTheFold&quot;:true}&quot;</a> data-component-name=&quot;Twitter2ToDOM&quot;&gt;</p><p>diffs.com and trees.software 🪾&quot;,&quot;username&quot;:&quot;ephraimduncan&quot;,&quot;name&quot;:&quot;Duncan&quot;,&quot;profile_image_url&quot;:&quot;<a href="https://pbs.substack.com/profile_images/1740764353408753664/uPGbBhm0_normal.jpg%22,%22date%22:%222026-04-23T14:53:29.000Z%22,%22photos%22:%5B%7B%22img_url%22:%22https://pbs.substack.com/media/HGmRa0DWAAEbgPx.jpg%22,%22link_url%22:%22https://t.co/qvFFXAq6oa%22%7D%5D,%22quoted_tweet%22:%7B%22full_text%22:%22https://t.co/paAoyBYDB0" target="_blank" rel="noreferrer">https://pbs.substack.com/profile_images/1740764353408753664/uPGbBhm0_normal.jpg&quot;,&quot;date&quot;:&quot;2026-04-23T14:53:29.000Z&quot;,&quot;photos&quot;:[{&quot;img_url&quot;:&quot;https://pbs.substack.com/media/HGmRa0DWAAEbgPx.jpg&quot;,&quot;link_url&quot;:&quot;https://t.co/qvFFXAq6oa&quot;}],&quot;quoted_tweet&quot;:{&quot;full_text&quot;:&quot;https://t.co/paAoyBYDB0</a> is so good, i want to build with it but i don&#39;t know what&quot;,&quot;username&quot;:&quot;ephraimduncan&quot;,&quot;name&quot;:&quot;Duncan&quot;,&quot;profile_image_url&quot;:&quot;<a href="https://pbs.substack.com/profile_images/1740764353408753664/uPGbBhm0_normal.jpg%22%7D,%22reply_count%22:22,%22retweet_count%22:24,%22like_count%22:533,%22impression_count%22:58333,%22expanded_url%22:null,%22video_url%22:null,%22belowTheFold%22:true%7D%22" target="_blank" rel="noreferrer">https://pbs.substack.com/profile_images/1740764353408753664/uPGbBhm0_normal.jpg&quot;},&quot;reply_count&quot;:22,&quot;retweet_count&quot;:24,&quot;like_count&quot;:533,&quot;impression_count&quot;:58333,&quot;expanded_url&quot;:null,&quot;video_url&quot;:null,&quot;belowTheFold&quot;:true}&quot;</a> data-component-name=&quot;Twitter2ToDOM&quot;&gt;</p><p>@ComfyUI \\n\\n&quot;,&quot;username&quot;:&quot;cpaik&quot;,&quot;name&quot;:&quot;Chris Paik&quot;,&quot;profile_image_url&quot;:&quot;<a href="https://pbs.substack.com/profile_images/448343484546568192/4-OsX4ne_normal.png%22,%22date%22:%222026-04-24T17:06:21.000Z%22,%22photos%22:%5B%5D,%22quoted_tweet%22:%7B%7D,%22reply_count%22:7,%22retweet_count%22:7,%22like_count%22:69,%22impression_count%22:12759,%22expanded_url%22:%7B%22url%22:%22https://docs.google.com/document/d/1-U2CZn9kXizjY9UWTidlyKpyPDgMUv0pIh38VxVN7NI/edit?usp=sharing%22,%22title%22:%22You" target="_blank" rel="noreferrer">https://pbs.substack.com/profile_images/448343484546568192/4-OsX4ne_normal.png&quot;,&quot;date&quot;:&quot;2026-04-24T17:06:21.000Z&quot;,&quot;photos&quot;:[],&quot;quoted_tweet&quot;:{},&quot;reply_count&quot;:7,&quot;retweet_count&quot;:7,&quot;like_count&quot;:69,&quot;impression_count&quot;:12759,&quot;expanded_url&quot;:{&quot;url&quot;:&quot;https://docs.google.com/document/d/1-U2CZn9kXizjY9UWTidlyKpyPDgMUv0pIh38VxVN7NI/edit?usp=sharing&quot;,&quot;title&quot;:&quot;You</a> Cannot Automate The Auteur&quot;,&quot;description&quot;:&quot;__________________\\u000bYou Cannot Automate The Auteur In 1839, Paul Delaroche witnessed the invention of photography and famously declared, “From today, painting is dead.” If he were alive today, he would be surprised to see how his report was greatly exaggerated. But he was also half-right. To the e...&quot;,&quot;domain&quot;:&quot;docs.google.com&quot;,&quot;image&quot;:&quot;<a href="https://pbs.substack.com/news_img/2047723879909498880/fkHGTvjw?format=png&amp;name=orig%22%7D,%22video_url%22:null,%22belowTheFold%22:true%7D%22" target="_blank" rel="noreferrer">https://pbs.substack.com/news_img/2047723879909498880/fkHGTvjw?format=png&amp;name=orig&quot;},&quot;video_url&quot;:null,&quot;belowTheFold&quot;:true}&quot;</a> data-component-name=&quot;Twitter2ToDOM&quot;&gt;</p><p>Find me on <a href="https://x.com/bentossell/" target="_blank" rel="noreferrer">X</a>, <a href="https://www.linkedin.com/in/ben-tossell-70453537/" target="_blank" rel="noreferrer">Linkedin</a>, or <a href="https://www.youtube.com/@bentossell694" target="_blank" rel="noreferrer">YouTube</a></p><p>Read <a href="https://bensbites.substack.com/about" target="_blank" rel="noreferrer">about me</a> and Ben’s Bites</p><p>📷 thumbnail by <a href="https://www.x.com/keshavatearth" target="_blank" rel="noreferrer">@keshavatearth</a></p><ul><li>sponsors who make this newsletter possible 😃</li></ul><p>Wanna partner with us for the next quarter?</p><p>Email us at <a href="mailto:shanice@bensbites.com" target="_blank" rel="noreferrer">shanice@bensbites.com</a> or <a href="mailto:k@bensbites.com" target="_blank" rel="noreferrer">k@bensbites.com</a></p><hr>',69)])])}const d=t(n,[["render",s]]);export{m as __pageData,d as default};
